SELECT CH.SEMESTRE FROM CALC_HORA_AULA_MEDIA CH JOIN SERVIDOR S ON CH.SIAPE = S.PK_SIAPE WHERE CH.ANO = 2024 AND LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%matemat%') AND LOWER(S.SIGLA_CAMPUS) = LOWER('val') GROUP BY CH.SEMESTRE HAVING COUNT(DISTINCT CH.SIAPE) = 6 ORDER BY CH.SEMESTRE